#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = fork();

 if (pid < 0) {
 // Fork failed
 fprintf(stderr, "Fork failed\n");
 return 1;
 } else if (pid == 0) {
 // Child process
 printf("Child: PID = %d, Parent PID = %d\n", 
 getpid(), getppid());
 printf("Child: Executing ls command\n");
 execlp("ls", "ls", "-l", NULL);
 } else {
 // Parent process
 printf("Parent: PID = %d, Child PID = %d\n", 
 getpid(), pid);
 wait(NULL); // Wait for child to complete
 printf("Parent: Child completed\n");
 }
 return 0;
}

import java.io.*;

public class ProcessExample {
 public static void main(String[] args) throws Exception {
 // Java uses ProcessBuilder instead of fork
 ProcessBuilder pb = new ProcessBuilder("ls", "-l");
 pb.inheritIO(); // Inherit parent's I/O

 System.out.println("Parent: Creating child process");
 Process process = pb.start();

 int exitCode = process.waitFor();
 System.out.println("Parent: Child exited with code " + exitCode);
 }
}
